/**
 * Inventory Module Types
 *
 * Type definitions for future inventory module implementation.
 * This file defines interfaces for stock management, suppliers,
 * and inventory tracking.
 *
 * @module modules/_stubs/inventory/types
 *
 * @example
 * ```typescript
 * import type {
 *   IInventoryService,
 *   InventoryItem,
 *   StockLevel,
 * } from '@/modules/_stubs/inventory';
 * ```
 */

// -----------------------------------------------------------------------------
// Enums
// -----------------------------------------------------------------------------

/**
 * Stock status
 */
export enum StockStatus {
  /** In stock */
  IN_STOCK = 'IN_STOCK',
  /** Low stock */
  LOW_STOCK = 'LOW_STOCK',
  /** Out of stock */
  OUT_OF_STOCK = 'OUT_OF_STOCK',
  /** Discontinued */
  DISCONTINUED = 'DISCONTINUED',
}

/**
 * Transaction type
 */
export enum StockTransactionType {
  /** Stock received */
  RECEIVED = 'RECEIVED',
  /** Stock sold (order) */
  SOLD = 'SOLD',
  /** Manual adjustment */
  ADJUSTED = 'ADJUSTED',
  /** Waste/spoilage */
  WASTE = 'WASTE',
  /** Transfer out */
  TRANSFER_OUT = 'TRANSFER_OUT',
  /** Transfer in */
  TRANSFER_IN = 'TRANSFER_IN',
  /** Return from customer */
  RETURN = 'RETURN',
}

/**
 * Unit of measure
 */
export enum UnitOfMeasure {
  /** Piece/unit */
  PIECE = 'PIECE',
  /** Kilogram */
  KG = 'KG',
  /** Gram */
  GRAM = 'GRAM',
  /** Liter */
  LITER = 'LITER',
  /** Milliliter */
  ML = 'ML',
  /** Box */
  BOX = 'BOX',
  /** Pack */
  PACK = 'PACK',
}

/**
 * Purchase order status
 */
export enum PurchaseOrderStatus {
  /** Draft */
  DRAFT = 'DRAFT',
  /** Submitted */
  SUBMITTED = 'SUBMITTED',
  /** Confirmed by supplier */
  CONFIRMED = 'CONFIRMED',
  /** Partially received */
  PARTIALLY_RECEIVED = 'PARTIALLY_RECEIVED',
  /** Fully received */
  RECEIVED = 'RECEIVED',
  /** Cancelled */
  CANCELLED = 'CANCELLED',
}

// -----------------------------------------------------------------------------
// Entity Types
// -----------------------------------------------------------------------------

/**
 * Inventory item
 */
export interface InventoryItem {
  /** Item ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Branch ID (if branch-specific) */
  branchId: string | null;
  /** SKU */
  sku: string;
  /** Item name */
  name: string;
  /** Description */
  description: string | null;
  /** Category */
  category: string | null;
  /** Unit of measure */
  unit: UnitOfMeasure;
  /** Current quantity */
  quantity: number;
  /** Minimum stock level */
  minStockLevel: number;
  /** Maximum stock level */
  maxStockLevel: number | null;
  /** Reorder point */
  reorderPoint: number;
  /** Cost per unit */
  costPerUnit: number;
  /** Supplier ID */
  supplierId: string | null;
  /** Stock status */
  status: StockStatus;
  /** Menu item IDs using this inventory item */
  linkedMenuItems: string[];
  /** Created at */
  createdAt: Date;
  /** Updated at */
  updatedAt: Date;
}

/**
 * Stock level (per branch)
 */
export interface StockLevel {
  /** Stock level ID */
  id: string;
  /** Inventory item ID */
  inventoryItemId: string;
  /** Branch ID */
  branchId: string;
  /** Current quantity */
  quantity: number;
  /** Reserved quantity (for pending orders) */
  reservedQuantity: number;
  /** Available quantity */
  availableQuantity: number;
  /** Status */
  status: StockStatus;
  /** Last counted at */
  lastCountedAt: Date | null;
  /** Updated at */
  updatedAt: Date;
}

/**
 * Stock transaction
 */
export interface StockTransaction {
  /** Transaction ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Branch ID */
  branchId: string;
  /** Inventory item ID */
  inventoryItemId: string;
  /** Transaction type */
  type: StockTransactionType;
  /** Quantity (positive for in, negative for out) */
  quantity: number;
  /** Balance after transaction */
  balance: number;
  /** Cost per unit at time of transaction */
  costPerUnit: number;
  /** Total cost */
  totalCost: number;
  /** Reference (order ID, PO number, etc.) */
  reference: string | null;
  /** Notes */
  notes: string | null;
  /** Created by user ID */
  createdBy: string;
  /** Created at */
  createdAt: Date;
}

/**
 * Supplier
 */
export interface Supplier {
  /** Supplier ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Supplier name */
  name: string;
  /** Contact name */
  contactName: string | null;
  /** Email */
  email: string | null;
  /** Phone */
  phone: string | null;
  /** Address */
  address: string | null;
  /** Tax ID */
  taxId: string | null;
  /** Payment terms (days) */
  paymentTerms: number;
  /** Is active */
  isActive: boolean;
  /** Notes */
  notes: string | null;
  /** Created at */
  createdAt: Date;
  /** Updated at */
  updatedAt: Date;
}

/**
 * Purchase order
 */
export interface PurchaseOrder {
  /** PO ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Branch ID */
  branchId: string;
  /** PO number */
  poNumber: string;
  /** Supplier ID */
  supplierId: string;
  /** Status */
  status: PurchaseOrderStatus;
  /** Order date */
  orderDate: Date;
  /** Expected delivery date */
  expectedDate: Date | null;
  /** Received date */
  receivedDate: Date | null;
  /** Items */
  items: PurchaseOrderItem[];
  /** Subtotal */
  subtotal: number;
  /** Tax */
  tax: number;
  /** Total */
  total: number;
  /** Notes */
  notes: string | null;
  /** Created by user ID */
  createdBy: string;
  /** Created at */
  createdAt: Date;
  /** Updated at */
  updatedAt: Date;
}

/**
 * Purchase order item
 */
export interface PurchaseOrderItem {
  /** Item ID */
  id: string;
  /** Inventory item ID */
  inventoryItemId: string;
  /** Quantity ordered */
  quantityOrdered: number;
  /** Quantity received */
  quantityReceived: number;
  /** Unit price */
  unitPrice: number;
  /** Total price */
  totalPrice: number;
}

/**
 * Waste record
 */
export interface WasteRecord {
  /** Record ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Branch ID */
  branchId: string;
  /** Inventory item ID */
  inventoryItemId: string;
  /** Quantity wasted */
  quantity: number;
  /** Reason */
  reason: string;
  /** Cost */
  cost: number;
  /** Recorded by user ID */
  recordedBy: string;
  /** Created at */
  createdAt: Date;
}

// -----------------------------------------------------------------------------
// Request Types
// -----------------------------------------------------------------------------

/**
 * Create inventory item request
 */
export interface CreateInventoryItemRequest {
  /** SKU */
  sku: string;
  /** Item name */
  name: string;
  /** Description */
  description?: string;
  /** Category */
  category?: string;
  /** Unit of measure */
  unit: UnitOfMeasure;
  /** Initial quantity */
  initialQuantity?: number;
  /** Minimum stock level */
  minStockLevel?: number;
  /** Maximum stock level */
  maxStockLevel?: number;
  /** Reorder point */
  reorderPoint?: number;
  /** Cost per unit */
  costPerUnit: number;
  /** Supplier ID */
  supplierId?: string;
  /** Linked menu items */
  linkedMenuItems?: string[];
}

/**
 * Update stock request
 */
export interface UpdateStockRequest {
  /** Inventory item ID */
  inventoryItemId: string;
  /** Branch ID */
  branchId: string;
  /** Transaction type */
  type: StockTransactionType;
  /** Quantity */
  quantity: number;
  /** Cost per unit (for receiving) */
  costPerUnit?: number;
  /** Reference */
  reference?: string;
  /** Notes */
  notes?: string;
}

/**
 * Stock adjustment request
 */
export interface StockAdjustmentRequest {
  /** Inventory item ID */
  inventoryItemId: string;
  /** Branch ID */
  branchId: string;
  /** New quantity (physical count) */
  newQuantity: number;
  /** Reason */
  reason: string;
}

/**
 * Create purchase order request
 */
export interface CreatePurchaseOrderRequest {
  /** Branch ID */
  branchId: string;
  /** Supplier ID */
  supplierId: string;
  /** Expected delivery date */
  expectedDate?: Date;
  /** Items */
  items: Array<{
    inventoryItemId: string;
    quantity: number;
    unitPrice: number;
  }>;
  /** Notes */
  notes?: string;
}

/**
 * Record waste request
 */
export interface RecordWasteRequest {
  /** Inventory item ID */
  inventoryItemId: string;
  /** Branch ID */
  branchId: string;
  /** Quantity */
  quantity: number;
  /** Reason */
  reason: string;
}

// -----------------------------------------------------------------------------
// Response Types
// -----------------------------------------------------------------------------

/**
 * Stock summary
 */
export interface StockSummary {
  /** Total items */
  totalItems: number;
  /** In stock count */
  inStock: number;
  /** Low stock count */
  lowStock: number;
  /** Out of stock count */
  outOfStock: number;
  /** Total value */
  totalValue: number;
  /** Items needing reorder */
  needsReorder: InventoryItem[];
}

/**
 * Low stock alert
 */
export interface LowStockAlert {
  /** Item */
  item: InventoryItem;
  /** Current quantity */
  currentQuantity: number;
  /** Min stock level */
  minStockLevel: number;
  /** Suggested order quantity */
  suggestedOrderQuantity: number;
  /** Last order date */
  lastOrderDate: Date | null;
}

// -----------------------------------------------------------------------------
// Service Interfaces
// -----------------------------------------------------------------------------

/**
 * Inventory service interface
 */
export interface IInventoryService {
  /**
   * Create inventory item
   */
  createItem(
    organizationId: string,
    request: CreateInventoryItemRequest
  ): Promise<InventoryItem>;

  /**
   * Update inventory item
   */
  updateItem(
    organizationId: string,
    itemId: string,
    request: Partial<CreateInventoryItemRequest>
  ): Promise<InventoryItem>;

  /**
   * Get inventory item
   */
  getItem(
    organizationId: string,
    itemId: string
  ): Promise<InventoryItem>;

  /**
   * List inventory items
   */
  listItems(
    organizationId: string,
    filters?: {
      status?: StockStatus;
      category?: string;
      branchId?: string;
    }
  ): Promise<InventoryItem[]>;

  /**
   * Get stock summary
   */
  getStockSummary(
    organizationId: string,
    branchId?: string
  ): Promise<StockSummary>;

  /**
   * Get low stock alerts
   */
  getLowStockAlerts(
    organizationId: string,
    branchId?: string
  ): Promise<LowStockAlert[]>;

  /**
   * Link menu item to inventory
   */
  linkMenuItem(
    organizationId: string,
    inventoryItemId: string,
    menuItemId: string,
    quantity: number
  ): Promise<void>;
}

/**
 * Stock service interface
 */
export interface IStockService {
  /**
   * Update stock
   */
  updateStock(
    organizationId: string,
    request: UpdateStockRequest
  ): Promise<StockTransaction>;

  /**
   * Adjust stock (physical count)
   */
  adjustStock(
    organizationId: string,
    request: StockAdjustmentRequest
  ): Promise<StockTransaction>;

  /**
   * Get stock level
   */
  getStockLevel(
    organizationId: string,
    inventoryItemId: string,
    branchId: string
  ): Promise<StockLevel>;

  /**
   * Reserve stock (for order)
   */
  reserveStock(
    organizationId: string,
    inventoryItemId: string,
    branchId: string,
    quantity: number,
    orderId: string
  ): Promise<boolean>;

  /**
   * Release reserved stock
   */
  releaseReservedStock(
    organizationId: string,
    orderId: string
  ): Promise<void>;

  /**
   * Commit reserved stock (order complete)
   */
  commitReservedStock(
    organizationId: string,
    orderId: string
  ): Promise<void>;

  /**
   * Get transaction history
   */
  getTransactionHistory(
    organizationId: string,
    inventoryItemId: string,
    branchId?: string,
    limit?: number
  ): Promise<StockTransaction[]>;

  /**
   * Record waste
   */
  recordWaste(
    organizationId: string,
    request: RecordWasteRequest
  ): Promise<WasteRecord>;
}

// -----------------------------------------------------------------------------
// Event Payload Types
// -----------------------------------------------------------------------------

/**
 * Stock updated event payload
 */
export interface StockUpdatedEventPayload {
  organizationId: string;
  branchId: string;
  inventoryItemId: string;
  previousQuantity: number;
  newQuantity: number;
  transactionType: StockTransactionType;
  timestamp: string;
}

/**
 * Low stock event payload
 */
export interface LowStockEventPayload {
  organizationId: string;
  branchId: string;
  inventoryItemId: string;
  itemName: string;
  currentQuantity: number;
  minStockLevel: number;
  timestamp: string;
}

/**
 * Out of stock event payload
 */
export interface OutOfStockEventPayload {
  organizationId: string;
  branchId: string;
  inventoryItemId: string;
  itemName: string;
  linkedMenuItems: string[];
  timestamp: string;
}

/**
 * Waste recorded event payload
 */
export interface WasteRecordedEventPayload {
  organizationId: string;
  branchId: string;
  inventoryItemId: string;
  quantity: number;
  reason: string;
  cost: number;
  timestamp: string;
}
